text:
Here are some patches that remove the use of SIGALRM in ping, and
one of the abuses of signal handlers.  This will also help with
bin/5658 if the RTT is smaller than the ping interval (e.g.  packets
won't be sent while pr_pack() is trying to print a packet).

  Bill

diff -u /usr/src/sbin/ping/ping.c ./ping.c
--- /usr/src/sbin/ping/ping.c	Fri Mar  6 05:07:12 1998
+++ ./ping.c	Mon May 25 11:46:07 1998
@@ -163,7 +163,6 @@

 static void fill(char *, char *);
 static u_short in_cksum(u_short *, int);
-static void catcher(int sig);
 static void check_status(void);
 static void finish(void) __dead2;
 static void pinger(void);
@@ -182,12 +181,12 @@
 	int argc;
 	char *const *argv;
 {
-	struct timeval timeout;
+	struct timeval last, intvl;
 	struct hostent *hp;
 	struct sockaddr_in *to;
 	struct termios ts;
 	register int i;
-	int ch, fdmask, hold, packlen, preload, sockerrno;
+	int ch, hold, packlen, preload, sockerrno, almost_done = 0;
 	struct in_addr ifaddr;
 	unsigned char ttl, loop;
 	u_char *datap, *packet;
@@ -376,6 +375,7 @@
 	/* record route option */
 	if (options & F_RROUTE) {
 #ifdef IP_OPTIONS
+		bzero(rspace, sizeof(rspace));
 		rspace[IPOPT_OPTVAL] = IPOPT_RR;
 		rspace[IPOPT_OLEN] = sizeof(rspace)-1;
 		rspace[IPOPT_OFFSET] = IPOPT_MINOFF;
@@ -438,11 +438,6 @@
 		err(EX_OSERR, "sigaction SIGINT");
 	}

-	si_sa.sa_handler = catcher;
-	if (sigaction(SIGALRM, &si_sa, 0) == -1) {
-		err(EX_OSERR, "sigaction SIGALRM");
-	}
-
 	si_sa.sa_handler = status;
 	if (sigaction(SIGINFO, &si_sa, 0) == -1) {
 		err(EX_OSERR, "sigaction");
@@ -457,35 +452,70 @@
 	while (preload--)		/* fire off them quickies */
 		pinger();

-	if ((options & F_FLOOD) == 0)
-		catcher(0);		/* start things going */
+	if (options & F_FLOOD) {
+		intvl.tv_sec = 0;
+		intvl.tv_usec = 10000;
+	} else {
+		intvl.tv_sec = interval;
+		intvl.tv_usec = 0;
+	}
+
+	pinger();			/* send the first ping */
+	gettimeofday(&last, NULL);

 	while (!finish_up) {
 		struct sockaddr_in from;
 		register int cc;
-		int fromlen;
+		int fromlen, n;
+		struct timeval timeout, now;
+		fd_set rfds;

 		check_status();
-		if (options & F_FLOOD) {
-			pinger();
-			timeout.tv_sec = 0;
-			timeout.tv_usec = 10000;
-			fdmask = 1 << s;
-			if (select(s + 1, (fd_set *)&fdmask, (fd_set *)NULL,
-			    (fd_set *)NULL, &timeout) < 1)
-				continue;
+		FD_ZERO(&rfds);
+		FD_SET(s, &rfds);
+		gettimeofday(&now, NULL);
+		timeout.tv_sec = last.tv_sec + intvl.tv_sec - now.tv_sec;
+		timeout.tv_usec = last.tv_usec + intvl.tv_usec - now.tv_usec;
+		while (timeout.tv_usec < 0) {
+			timeout.tv_usec += 1000000;
+			timeout.tv_sec--;
 		}
-		fromlen = sizeof(from);
-		if ((cc = recvfrom(s, (char *)packet, packlen, 0,
-		    (struct sockaddr *)&from, &fromlen)) < 0) {
-			if (errno == EINTR)
+		while (timeout.tv_usec > 1000000) {
+			timeout.tv_usec -= 1000000;
+			timeout.tv_sec++;
+		}
+		if (timeout.tv_sec < 0)
+			timeout.tv_sec = timeout.tv_usec = 0;
+		n = select(s + 1, &rfds, NULL, NULL, &timeout);
+		if (n == 1) {
+			fromlen = sizeof(from);
+			if ((cc = recvfrom(s, (char *)packet, packlen, 0,
+			    (struct sockaddr *)&from, &fromlen)) < 0) {
+				if (errno == EINTR)
+					continue;
+				perror("ping: recvfrom");
 				continue;
-			perror("ping: recvfrom");
-			continue;
+			}
+			pr_pack((char *)packet, cc, &from);
+			if (npackets && nreceived >= npackets)
+				break;
+		}
+		if (n == 0) {
+			if (!npackets || ntransmitted < npackets)
+				pinger();
+			else {
+				if (almost_done)
+					break;
+				almost_done = 1;
+				if (nreceived) {
+					intvl.tv_sec = 2 * tmax / 1000;
+					if (!intvl.tv_sec)
+						intvl.tv_sec = 1;
+				} else
+					intvl.tv_sec = MAXWAIT;
+			}
+			gettimeofday(&last, NULL);
 		}
-		pr_pack((char *)packet, cc, &from);
-		if (npackets && nreceived >= npackets)
-			break;
 	}
 	finish();
 	/* NOTREACHED */
@@ -506,54 +536,12 @@
 }

 /*
- * catcher --
- *	This routine causes another PING to be transmitted, and then
- * schedules another SIGALRM for 1 second from now.
- *
- * bug --
- *	Our sense of time will slowly skew (i.e., packets will not be
- * launched exactly at 1-second intervals).  This does not affect the
- * quality of the delay and loss statistics.
- */
-static void
-catcher(int sig)
-{
-	int waittime;
-	struct sigaction si_sa;
-
-	pinger();
-
-	if (!npackets || ntransmitted < npackets)
-		(void)alarm((u_int)interval);
-	else {
-		if (nreceived) {
-			waittime = 2 * tmax / 1000;
-			if (!waittime)
-				waittime = 1;
-		} else
-			waittime = MAXWAIT;
-
-		si_sa.sa_handler = stopit;
-		sigemptyset(&si_sa.sa_mask);
-		si_sa.sa_flags = 0;
-		if (sigaction(SIGALRM, &si_sa, 0) == -1) {
-			finish_up = 1;
-			return;
-		}
-		(void)alarm((u_int)waittime);
-	}
-}
-
-/*
  * pinger --
  *	Compose and transmit an ICMP ECHO REQUEST packet.  The IP packet
  * will be added on by the kernel.  The ID field is our UNIX process ID,
  * and the sequence number is an ascending integer.  The first 8 bytes
  * of the data portion are used to hold a UNIX "timeval" struct in host
  * byte-order, to compute the round-trip time.
- *
- * bug --
- *	this does far too much to be called from a signal handler.
  */
 static void
 pinger(void)
